import React, { useState, useEffect, useRef } from 'react';
import { getHero, uploadHeroImage, deleteHeroImage } from '../services/api';
import { useAuth } from '../context/AuthContext';
import Toast from '../components/Toast';

export default function ManageHeroPage() {
  const { token } = useAuth();
  const [images, setImages] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const fileRef = useRef(null);
  const [selectedFile, setSelectedFile] = useState(null);
  const [selectedName, setSelectedName] = useState('');

  const load = async () => {
    try {
      setLoading(true); setError('');
      const res = await getHero();
      if (res.success) setImages(res.data.images || []);
      else setError(res.message || 'Failed to load');
    } catch (err) { setError(err.message || 'Failed to load'); }
    finally { setLoading(false); }
  };

  useEffect(() => { load(); }, []);

  const handleFileSelect = (e) => {
    const f = e.target.files?.[0];
    if (!f) return;
    setSelectedFile(f);
    setSelectedName(f.name);
  };

  const handleUploadSubmit = async () => {
    if (!selectedFile) return setError('Choose a file first');
    const fd = new FormData();
    fd.append('image', selectedFile);
    try {
      setLoading(true); setError(''); setSuccess('');
      const res = await uploadHeroImage(token, fd);
      if (res.success) {
        setImages(res.data.images || []);
        setSuccess('Image uploaded');
        setSelectedFile(null);
        setSelectedName('');
        if (fileRef.current) fileRef.current.value = '';
      } else setError(res.message || 'Upload failed');
    } catch (err) { setError(err.message || 'Upload failed'); }
    finally { setLoading(false); }
  };

  const handleDelete = async (publicId) => {
    if (!window.confirm('Delete this hero image?')) return;
    try {
      setLoading(true); setError(''); setSuccess('');
      const res = await deleteHeroImage(token, publicId);
      if (res.success) {
        setImages(prev => prev.filter(i => i.publicId !== publicId));
        setSuccess('Deleted');
      } else setError(res.message || 'Delete failed');
    } catch (err) { setError(err.message || 'Delete failed'); }
    finally { setLoading(false); }
  };

  const handleView = (url) => {
    if (!url) return;
    window.open(url, '_blank', 'noopener,noreferrer');
  };

  return (
    <div className="manage-page">
      <h2 style={{ marginBottom: 12 }}>Hero Images</h2>
      <Toast message={error} type="error" onClose={() => setError('')} />
      <Toast message={success} type="success" onClose={() => setSuccess('')} />

      <div className="manage-toolbar">
        <div className="search-box">
          <input ref={fileRef} type="file" accept="image/*" onChange={handleFileSelect} style={{ display: 'none' }} />
          <button type="button" className="view-btn" onClick={() => fileRef.current && fileRef.current.click()}>Choose Image</button>
          <div style={{ marginLeft: 12, fontSize: 14, color: '#6b7280' }}>{selectedName || 'No file chosen'}</div>
        </div>

        <div className="toolbar-right">
          <button type="button" className="bulk-delete-btn" onClick={handleUploadSubmit}>Upload</button>
        </div>
      </div>

      <div className="stats-strip">
        <span>Total: <strong>{images.length}</strong> images</span>
      </div>

      {loading ? <div>Loading...</div> : (
        <div className="cards-grid">
          {images.length ? images.map(img => (
            <div key={img.publicId} className="article-card">
              <div className="article-card-top">
                <div className="card-top-left">
                  <span className="card-num">&nbsp;</span>
                </div>
                <div className="card-chips">
                  <span className="chip-size">{img.fileSize ? `${(img.fileSize/1024/1024).toFixed(2)} MB` : ''}</span>
                </div>
              </div>

              <div className="article-card-title">{img.fileName || 'Untitled'}</div>

              <div className="article-card-file" style={{ justifyContent: 'center', padding: 16 }}>
                <img src={img.url} alt={img.fileName || ''} style={{ maxHeight: 180, maxWidth: '100%', objectFit: 'cover' }} />
              </div>

              <div className="article-card-actions">
                <button className="act-btn act-view" onClick={() => handleView(img.url)}>View</button>
                <button className="act-btn act-delete" onClick={() => handleDelete(img.publicId)}>Delete</button>
              </div>
            </div>
          )) : <div>No hero images configured.</div>}
        </div>
      )}
    </div>
  );
}
